  render: () => <Feature />,
  play: async ({ canvas }) => {
    const heading = canvas.getByText('100% handcraft growth');
    // The heading uses text-[color:var(--primary-font-color)] which is rgb(147, 157, 250)
    await expect(getComputedStyle(heading).color).toBe('rgb(147, 157, 250)');
  },
});

