 24→export default function App() {
 25→  const [user, setUser] = useState(null);
 26→  const [loggedIn, setLoggedIn] = useState(false);
 27→  const [triggeredLogout, setTriggeredLogout] = useState(false);
 28→
 29→  useEffect(() => {
 30→    if (
 31→      loggedIn &&
 32→      sessionStorage.getItem("loggedIn") === null &&
 33→      !triggeredLogout
 34→    ) {
 35→      sessionStorage.setItem("loggedIn", "true");
 36→    }
 37→    if (triggeredLogout && sessionStorage.getItem("loggedIn") !== null) {
 38→      sessionStorage.removeItem("loggedIn");
 39→      sessionStorage.removeItem("user");
 40→    }
 41→    if (sessionStorage.getItem("loggedIn") !== null && !triggeredLogout) {
 42→      setLoggedIn(true);
 43→      const jsonUser = sessionStorage.getItem("user");
 44→      if (jsonUser) {
 45→        setUser(JSON.parse(jsonUser));
 46→      }
 47→    }
 48→  }, [loggedIn, triggeredLogout]);
 49→
 50→  useEffect(() => {
 51→    const jsonUser = sessionStorage.getItem("user");
 52→    if (jsonUser) {
 53→      const userData = JSON.parse(jsonUser);
 54→      setUser(userData);
 55→      setLoggedIn(true);
 56→    }
 57→  }, []);
 58→
 59→  const findUserByEmail = (records, email) =>
 60→    records.find((record) => record.fields.email === email);
 61→
 62→  const retrieveDatabase = async (email, password = undefined) => {
 63→    try {
 64→      const response = await fetch(import.meta.env.VITE_AIRTABLE_SERVER_URL);
 65→      const data = await response.json();
 66→
 67→      if (data) {
 68→        const userByEmail = findUserByEmail(data.records, email);
 69→        if (userByEmail) {
 70→          if (loggedIn && userByEmail.fields.email === user.email) {
 71→            return true;
 72→          }
 73→          if (userByEmail.fields.password === password) {
 74→            const userData = {
 75→              id: userByEmail.id,
 76→              createdTime: moment(userByEmail.createdTime)
 77→                .utc()
 78→                .format("YYYY-MM-DD"),
 79→              email: userByEmail.fields.email,
 80→              fullname: userByEmail.fields.fullname,
 81→              gender: userByEmail.fields.gender,
 82→              plan: userByEmail.fields.plan,
 83→              password: userByEmail.fields.password,
 84→            };
 85→
 86→            setUser(userData);
 87→            sessionStorage.setItem("user", JSON.stringify(userData));
 88→
 89→            return true;
 90→          }
 91→          return true;
 92→        } else {
 93→          return false;
 94→        }
 95→      }
 96→    } catch (err) {
 97→      return false;
 98→    }
 99→  };
100→  const userEmailExists = async (email) => {
101→    try {
102→      const user = await retrieveDatabase(email.toLowerCase());
103→      return !!user;
104→    } catch (error) {
105→      console.log("Failed to check user existence:", error);
106→      return false;
107→    }
108→  };
109→  const registerUser = async (data) => {
110→    const { email, password, fullname } = data;
111→    const id = uuidv4();
112→    const checkUser = await userEmailExists(data.email);
113→
114→    if (checkUser) {
115→      return false;
116→    } else {
117→      try {
118→        edgyBase("users").create([
119→          {
120→            fields: {
121→              id: id,
122→              email: email.toLowerCase(),
123→              password: password,
124→              fullname: fullname,
125→            },
126→          },
127→        ]);
128→        return true;
129→      } catch (error) {
130→        console.error(error);
131→      }
132→    }
133→  };
134→
135→  const updateUser = async (userId, formValue) => {
136→    const key = Object.keys(formValue)[0];
137→    const value = Object.values(formValue)[0];
138→    if (key === "email") {
139→      let checkUser = await userEmailExists(value);
140→      if (checkUser) return { success: false, reason: "email" };
141→    }
142→
143→    try {
144→      const response = await fetch(import.meta.env.VITE_AIRTABLE_SERVER_URL, {
145→        method: "POST",
146→        headers: {
147→          "content-type": "application/json",
148→        },
149→        body: JSON.stringify({ userId, formValue }),
150→      });
151→      const result = await response.json();
152→      if (!result.success) return { success: false, reason: result.reason };
153→
154→      setUser({ ...user, [key]: value });
155→      sessionStorage.setItem("user", JSON.stringify({ ...user, [key]: value }));
156→      return { success: true };
157→    } catch (error) {
158→      return { success: false, reason: error };
159→    }
160→  };
161→
162→  const deleteUser = (userId) => {
163→    edgyBase("users").destroy([userId], function (err, deletedRecords) {
164→      if (err) {
165→        console.error(err);
166→        return;
167→      }
168→    });
169→    setLoggedIn(false);
170→  };
171→
172→  return (
173→    <Router>
174→      <Navigation
175→        loggedIn={loggedIn}
176→        setLoggedIn={setLoggedIn}
177→        setTriggeredLogout={setTriggeredLogout}
178→      />
179→      <Routes>
180→        <Route path="/" element={<Landing loggedIn={loggedIn} />} />
181→        <Route path="/contact" element={<Contact />} />
182→        <Route path="/pricing" element={<Pricing loggedIn={loggedIn} />} />
183→        <Route path="/faq" element={<Faq />} />
184→        <Route path="/blog" element={<Blog />} />
185→        <Route path="/blog/:name" element={<BlogPost />} />
186→        <Route path="/about" element={<About />} />
187→        <Route path="/terms" element={<Terms />} />
188→        <Route path="/refunds" element={<Refunds />} />
189→        <Route path="/privacy" element={<Privacy />} />
190→        <Route path="/jobs" element={<Jobs />} />
191→        <Route
192→          path="/sign-in"
193→          element={
194→            loggedIn ? (
195→              <Profile
196→                retrieveDatabase={retrieveDatabase}
197→                user={user}
198→                updateUser={updateUser}
199→                deleteUser={deleteUser}
200→                setLoggedIn={setLoggedIn}
201→                setTriggeredLogout={setTriggeredLogout}
202→              />
203→            ) : (
204→              <SignIn
205→                retrieveDatabase={retrieveDatabase}
206→                user={user}
207→                setLoggedIn={setLoggedIn}
208→              />
209→            )
210→          }
211→        />
212→        <Route
213→          path="/sign-up"
214→          element={
215→            loggedIn ? (
216→              <Profile
217→                retrieveDatabase={retrieveDatabase}
218→                user={user}
219→                updateUser={updateUser}
220→                deleteUser={deleteUser}
221→                setLoggedIn={setLoggedIn}
222→                setTriggeredLogout={setTriggeredLogout}
223→              />
224→            ) : (
225→              <SignUp
226→                retrieveDatabase={retrieveDatabase}
227→                user={user}
228→                registerUser={registerUser}
229→              />
230→            )
231→          }
232→        />
233→        <Route
234→          path="/profile"
235→          element={
236→            loggedIn ? (
237→              <Profile
238→                retrieveDatabase={retrieveDatabase}
239→                user={user}
240→                updateUser={updateUser}
241→                deleteUser={deleteUser}
242→                setLoggedIn={setLoggedIn}
243→                setTriggeredLogout={setTriggeredLogout}
244→              />
245→            ) : (
246→              <NotFound />
247→            )
248→          }
249→        />
250→        <Route path="*" element={<NotFound />} />
251→      </Routes>
252→      <Footer />
253→    </Router>
254→  );
255→}
