  play: async ({ canvas }) => {
    await expect(
      canvas.getByText('Valuable Metrics')
    ).toBeVisible();
    await expect(
      canvas.getByText('TRUSTED BY THOUSANDS OF BUSINESS OWNERS')
    ).toBeVisible();
  },
});

